import * as d3 from "d3"
import data from './assets/DataVisualizationD3Assignment.csv'

const margin = {top: 20, right: 10, bottom: 70, left: 100}

let WIDTH
let HEIGHT = 500 - margin.top - margin.bottom;

class ScatterPlotD3 {
    
    constructor(element) {
        let rect = element.getBoundingClientRect();
        WIDTH = rect.width - margin.left - margin.right
        HEIGHT = rect.height - margin.top - margin.bottom
        d3.select(element).select("svg").remove()
        this.draw(element)
    }

    draw(element) {
        const svg = d3.select(element)
                        .append("svg")
                        .attr("width", WIDTH + margin.right + margin.left)
                        .attr("height", HEIGHT + margin.top + margin.bottom)

        let g = svg.append("g")
            .attr("transform", `translate(${ window.innerWidth > 500 ? margin.left: 40} ,${margin.top})`)

        let legend = svg.append("g")
                        .attr("transform", "translate(" + (WIDTH+70) + "," + (HEIGHT-300) + ")")

        const y = d3.scaleLinear()
                    .domain([0, 100])
                    .range([HEIGHT, 0])
                g.append("g")
                    .attr("transform", "translate(0, 0)" )
                    .call(d3.axisLeft(y))
                    .attr("font-size", "0.5em");
                   
        const x = d3.scaleLinear()
                    .domain([0, 100])
                    .range([0, WIDTH/2])
                g.append("g")
                    .attr("transform", "translate(0, " + HEIGHT + ")")
                    .call(d3.axisBottom(x))
                    .attr("font-size", "0.5em");

            var clusterColor = d3.scaleOrdinal(d3.schemeCategory10);
            
        let yLabel = g.append("text")
                        .attr("class", "y axis-label")
                        .attr("x", - HEIGHT/2)
                        .attr("y", -30)
                        .attr("transform", "rotate(-90)")
                        .attr("font-size", `1em`)
                        .attr("text-anchor", "middle")
                        .text("Future Competitiveness")

        let xLabel = g.append("text")
                        .attr("class", "y axis-label")
                        .attr("x", WIDTH/3)
                        .attr("y", HEIGHT+ 50)
                        .attr("font-size", "1em")
                        .attr("text-anchor", "middle")
                        .text("Current Competitiveness")
        
    d3.csv(data)
        .then(data => {

        let clusters = []
        let categories = []
        let clusterColumn = ''
        let category = ''
        let selectedCategory = 'All'
        let currentCompetitiveness = ''
        let futureCompetitiveness = ''
        let industries = ["Overall", "Automotive", "Consumer Products", "Industrial Products", "High-Tech"]
        let industry = "Overall"
        let year = '2013'
        let years = ["2013", "2016"]

        switch(industry) {
            case "Overall":
                clusterColumn = '2016_Cluster'
                if(year === "2013") {
                    category = '2013_Category'
                    currentCompetitiveness = '2013_Current_Competitiveness'
                    futureCompetitiveness = '2013_Future_Competitiveness'
                }
                else {
                    category = '2016_Category'
                    currentCompetitiveness = '2016_Current_Competitiveness'
                    futureCompetitiveness = '2016_Future_Competitiveness'
                }
                break
            case "Automotive":
                clusterColumn = "Auto_Cluster"
                category = 'Auto_Category'
                currentCompetitiveness = 'Auto_Current_Competitiveness'
                futureCompetitiveness = 'Auto_Future_Competitiveness'
                break
            case "ConsumerProducts":
                clusterColumn = "Consumer_Cluster"
                category = 'Consumer_Category'
                currentCompetitiveness = 'Consumer_Current_Competitiveness'
                futureCompetitiveness = 'Consumer_Future_Competitiveness'
                break
            case "IndustrialProducts":
                clusterColumn = "Industry_Cluster"
                category = 'Industry_Category'
                currentCompetitiveness = 'Industry_Current_Competitiveness'
                futureCompetitiveness = 'Industry_Future_Competitiveness'
                break
            case "High-Tech":
                clusterColumn = "Hitech_Cluster"
                category = 'Hitech_Category'
                currentCompetitiveness = 'Hitech_Current_Competitiveness'
                futureCompetitiveness = 'Hitech_Future_Competitiveness'
                break
            default: 
                break
        }

        for (let i = 0; i < data.length; i++) {
            if(!clusters.includes(data[i][clusterColumn])) {
                clusters.push(data[i][clusterColumn])
            }
        }

        for (let i = 0; i < data.length; i++) {
            if(!categories.includes(data[i][category])) {
                categories.push(data[i][category])
            }
        }

        categories.unshift("All")

        var industryOptions = d3.select("#select-industry")
                    .on('change', d => {
                        industry = d.target.value
                        plot(selectedCategory, industry, year)
                    })
                    .selectAll('option')
                    .data(industries)
                    .enter()
                    .append("option")

        industryOptions.text(d => d)
                    .attr("value", d => d)
 
        var yearOptions = d3.select("#select-year")
                    .on('change', d => {
                        year = d.target.value
                        plot(selectedCategory, industry, year)
                    })
                    .selectAll('option')
                    .data(years)
                    .enter()
                    .append("option")

        yearOptions.text(d => d)
                .attr("value", d => d)

        var categoryOptions = d3.select("#select-category")
                    .on('change', (d) => {
                        selectedCategory = d.target.value
                        plot(selectedCategory, industry, year)
                    })
                    .selectAll("option")
                    .data(categories)
                    .enter()
                    .append("option")
                    
        categoryOptions.text((d) => d)
                .attr("value", (d) => d);

        function wrap(text, width) {
            text.each(function () {
                var text = d3.select(this),
                    words = text.text().split(/\s+/).reverse(),
                    word,
                    line = [],
                    lineNumber = 0,
                    lineHeight = 1.1, // ems
                    x = text.attr("x"),
                    y = text.attr("y"),
                    dy = 0, //parseFloat(text.attr("dy")),
                    tspan = text.text(null)
                                .append("tspan")
                                .attr("x", x)
                                .attr("y", y)
                                .attr("dy", dy + "em");
                while (word = words.pop()) {
                    line.push(word);
                    tspan.text(line.join(" "));
                    if (tspan.node().getComputedTextLength() > width) {
                        line.pop();
                        tspan.text(line.join(" "));
                        line = [word];
                        tspan = text.append("tspan")
                                    .attr("x", x)
                                    .attr("y", y)
                                    .attr("dy", ++lineNumber * lineHeight + dy + "em")
                                    .text(word);
                    }
                }
            });
        }

        clusters.forEach((cluster, i) => {
            let legendRow = legend.append("g")
            .attr("transform", `translate(${-WIDTH/3},
                    ${window.innerWidth > 850 ? i*20: 
                    window.innerWidth > 514 ? i*30:
                    window.innerWidth > 350 ? i*35: i*35})`)

            legendRow.append("rect")
                .attr("width", 10)
                .attr("height", 10)
                .attr("fill", clusterColor(cluster))

            legendRow.append("text")
                .attr("x", 10)
                .attr("y", 10)
                .attr("text-anchor", "start")
                .attr("font-size", window.innerWidth > 1321 ? "15px": 
                                    window.innerWidth > 350 ? "10px": "8px")
                .text(cluster)
                .call(wrap, window.innerWidth > 850 ? 450: 
                            window.innerWidth > 677 ? 200:
                            window.innerWidth > 514 ? 150: 
                            window.innerWidth > 350 ? 100: 70)
        })

        function plot(selectedCategory, industry, year) {
            console.log(selectedCategory)
            var circles = g.append('g')
                    .selectAll("circle")
                    .data(data)

            svg.selectAll("circle.enter").transition().attr('r', 0).remove()

            circles
                .enter()
                .append("circle")
                .attr("class", "enter")
                .attr("cx", function (d) { 
                    if(selectedCategory === "All") {
                        console.log("Inside All")
                        switch(industry) {
                            case "Overall":
                                if(year === "2013") {
                                    return x(d['2013_Current_Competitiveness']); 
                                } 
                                else {
                                    return x(d['2016_Current_Competitiveness']); 
                                }
                            case "Automotive":
                                return x(d['Auto_Current_Competitiveness']);
                            case "Consumer Products":
                                return x(d['Consumer_Current_Competitiveness']);
                            case "Industrial Products":
                                return x(d['Industry_Current_Competitiveness']);
                            case "High-Tech":
                                return x(d['Hitech_Current_Competitiveness']); 
                            default:
                                return x(0)
                        }
                    }
                    else {
                        if(d[category] === selectedCategory) {
                            console.log(selectedCategory)
                            switch(industry) {
                                case "Overall":
                                    if(year === "2013") {
                                        return x(d['2013_Current_Competitiveness']); 
                                    } 
                                    else {
                                        return x(d['2016_Current_Competitiveness']); 
                                    }
                                case "Automotive":
                                    return x(d['Auto_Current_Competitiveness']);
                                case "Consumer Products":
                                    return x(d['Consumer_Current_Competitiveness']);
                                case "Industrial Products":
                                    return x(d['Industry_Current_Competitiveness']);
                                case "High-Tech":
                                    return x(d['Hitech_Current_Competitiveness']); 
                                default:
                                    return x(0)
                            }
                        }
                    }
                })
                .attr("cy", function (d) {
                    
                    if(selectedCategory === "All") {
                        switch(industry) {
                            case "Overall":
                                if(year === "2013") {
                                    return y(d['2013_Future_Competitiveness']); 
                                } 
                                else {
                                    return y(d['2016_Future_Competitiveness']); 
                                }
                            case "Automotive":
                                return y(d['Auto_Future_Competitiveness']);
                            case "Consumer Products":
                                return y(d['Consumer_Future_Competitiveness']);
                            case "Industrial Products":
                                return y(d['Industry_Future_Competitiveness']);
                            case "High-Tech":
                                return y(d['Hitech_Future_Competitiveness']); 
                            default:
                                return y(HEIGHT)
                        }
                    }
                    else {
                        if(d[category] === selectedCategory) {
                            switch(industry) {
                                case "Overall":
                                    if(year === "2013") {
                                        return y(d['2013_Future_Competitiveness']); 
                                    } 
                                    else {
                                        return y(d['2016_Future_Competitiveness']); 
                                    }
                                case "Automotive":
                                    return y(d['Auto_Future_Competitiveness']);
                                case "Consumer Products":
                                    return y(d['Consumer_Future_Competitiveness']);
                                case "Industrial Products":
                                    return y(d['Industry_Future_Competitiveness']);
                                case "High-Tech":
                                    return y(d['Hitech_Future_Competitiveness']); 
                                default:
                                    return y(HEIGHT)
                            }
                        }
                    }
                })
                .attr("r", 5)
                .style("fill", (d) => { return clusterColor(d[clusterColumn]); })
                .append('title')
                .text((d) => { 
                    return `Current: ${d[currentCompetitiveness]}, Future: ${d[futureCompetitiveness]}, 
                            Category: ${d[category]}`
            })
        }
        plot(selectedCategory, industry, year) 
        })
        .catch(error => {
            console.log(error)
        })
    }
}

export default ScatterPlotD3